        Err("provider setup not configured".into())
    }

    async fn oauth_start(&self, _p: Value) -> ServiceResult {
        Err("provider setup not configured".into())
    }

    async fn oauth_complete(&self, _p: Value) -> ServiceResult {
        Err("provider setup not configured".into())
    }

